#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char name[25];
        int score, age;
        scanf("%s %d %d", name, &score, &age);
        if (score > 10 && age > 20) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
    }
    return 0;
}

