code.Python3:
#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    T = int(data[0])
    out = []
    for i in range(1, T+1):
        parts = data[i].split()
        score = int(parts[1])
        age = int(parts[2])
        out.append("YES" if score > 10 and age > 20 else "NO")
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    main()

